#[cfg(test)]
mod tests {
    use super::*;
    use half::f16;
    use proptest::prelude::*;

    /// Reference scalar implementation for comparison
    fn dot_product_scalar(a: &[f16], b: &[f16]) -> f32 {
        a.iter().zip(b).map(|(x, y)| f32::from(*x) * f32::from(*y)).sum()
    }

    #[test]
    fn test_empty_vectors() {
        let a: Vec<f16> = vec![];
        let b: Vec<f16> = vec![];
        assert_eq!(dot_product_f16_simd(&a, &b), 0.0);
    }

    #[test]
    fn test_single_element() {
        let a = vec![f16::from_f32(2.0)];
        let b = vec![f16::from_f32(3.0)];
        let result = dot_product_f16_simd(&a, &b);
        assert!((result - 6.0).abs() < 1e-3);
    }

    #[test]
    fn test_exactly_8_elements() {
        let a: Vec<f16> = (1..=8).map(|i| f16::from_f32(i as f32)).collect();
        let b: Vec<f16> = (1..=8).map(|i| f16::from_f32(i as f32)).collect();
        let expected = dot_product_scalar(&a, &b);
        let result = dot_product_f16_simd(&a, &b);
        assert!((result - expected).abs() / expected.abs() < 1e-5);
    }

    #[test]
    fn test_remainder_handling() {
        // Test 7, 9, 15, 17 elements (edge cases around 8)
        for len in [7, 9, 15, 17, 23, 31, 33] {
            let a: Vec<f16> = (0..len).map(|i| f16::from_f32(i as f32 * 0.1)).collect();
            let b: Vec<f16> = (0..len).map(|i| f16::from_f32(i as f32 * 0.1)).collect();
            let expected = dot_product_scalar(&a, &b);
            let result = dot_product_f16_simd(&a, &b);
            let relative_error = (result - expected).abs() / expected.abs().max(1e-10);
            assert!(relative_error < 1e-4, 
                "len={}: expected={}, got={}, rel_err={}", len, expected, result, relative_error);
        }
    }

    #[test]
    fn test_real_embedding_dimensions() {
        // Test actual embedding sizes used in practice
        for dim in [128, 256, 384, 512, 768, 1024, 1536] {
            let a: Vec<f16> = (0..dim).map(|i| f16::from_f32((i as f32).sin())).collect();
            let b: Vec<f16> = (0..dim).map(|i| f16::from_f32((i as f32).cos())).collect();
            let expected = dot_product_scalar(&a, &b);
            let result = dot_product_f16_simd(&a, &b);
            let relative_error = (result - expected).abs() / expected.abs().max(1e-10);
            assert!(relative_error < 1e-4, "dim={}: rel_err={}", dim, relative_error);
        }
    }

    proptest! {
        #[test]
        fn prop_matches_scalar(len in 0usize..2048) {
            let a: Vec<f16> = (0..len).map(|i| f16::from_f32((i as f32) * 0.001)).collect();
            let b: Vec<f16> = (0..len).map(|i| f16::from_f32((i as f32) * 0.001)).collect();
            let expected = dot_product_scalar(&a, &b);
            let result = dot_product_f16_simd(&a, &b);
            if expected.abs() > 1e-10 {
                let relative_error = (result - expected).abs() / expected.abs();
                prop_assert!(relative_error < 1e-4);
            }
        }
    }
