  --accent: oklch(0.55 0.18 75);
}

[data-theme="light"] .message {
  background: oklch(1 0 0 / 0.9);
  box-shadow: 0 2px 8px oklch(0 0 0 / 0.08);
}
```

## Print Styles
```css
@media print {
  body::before { display: none; }
  .toolbar, .floating-nav, .theme-toggle { display: none; }
  .message {
    background: white;
    backdrop-filter: none;
    box-shadow: none;
    border: 1px solid #ccc;
    break-inside: avoid;
  }
  .tool-popover { display: none; }
  .tool-badge { border: 1px solid #666; }
}
```

## High Contrast Mode
```css
@media (prefers-contrast: high) {
  .tool-badge {
    border-width: 2px;
  }
  .message {
    border-width: 2px;
  }
}
```

## Responsive (Mobile)
```css
@media (max-width: 640px) {
  .message-header-right {
    gap: var(--space-1);
  }
  .tool-badge {
    width: 32px;
    height: 32px;  /* Larger touch targets */
  }
  .tool-popover {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    max-width: 100%;
    border-radius: var(--radius-lg) var(--radius-lg) 0 0;
  }
}
```

## Animations
```css
@keyframes fadeSlideIn {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

.message {
  animation: fadeSlideIn 0.35s ease-out forwards;
}

@media (prefers-reduced-motion: reduce) {
  .message { animation: none; }
  .tool-badge { transition: none; }
}
```

